w('<div style="font-size:12px;opacity:.85;font-family:Arial,sans-serif">Key terms: <span style="background:rgba(255,255,255,.2);padding:2px 7px;border-radius:10px;margin-right:5px">at the expense of</span><span style="background:rgba(255,255,255,.2);padding:2px 7px;border-radius:10px;margin-right:5px">customers</span><span style="background:rgba(255,255,255,.2);padding:2px 7px;border-radius:10px">employees</span></div>\n')
w('</div>\n')
w('<div class="alert info"><span>&#128161;</span><div><strong>Key analytical move:</strong> "At the expense of" means zero-sum &mdash; one party gains ONLY because another loses. You must test whether each relationship is zero-sum or positive-sum.</div></div>\n')
w('<div class="sh">&#128100; The Four Possible Answers</div>\n')
w('<div class="sg" style="grid-template-columns:repeat(auto-fit,minmax(200px,1fr))">\n')
w('<div class="sc" style="border-top:4px solid var(--red)"><div class="si">&#128308;</div><div class="sv" style="color:var(--red)">Both</div><div class="sl">Customers AND employees exploited</div></div>\n')
w('<div class="sc" style="border-top:4px solid var(--q1)"><div class="si">&#128309;</div><div class="sv" style="color:var(--q1)">Customers Only</div><div class="sl">Monopoly pricing, but workers fine</div></div>\n')
w('<div class="sc" style="border-top:4px solid var(--gold)"><div class="si">&#128992;</div><div class="sv" style="color:var(--gold)">Employees Only</div><div class="sl">Customers benefit, workers exploited</div></div>\n')
w('<div class="sc" style="border-top:4px solid var(--green)"><div class="si">&#128994;</div><div class="sv" style="color:var(--green)">Neither</div><div class="sl">Positive-sum wealth creation</div></div>\n')
w('</div>\n')
w('<div class="sh">&#128202; The Evidence</div>\n')
w('<div class="dg">\n')
w('<div class="ds gs"><div class="dh g">&#128994; NOT at Customers\' Expense</div>\n')
