w('<div class="dp"><div><strong>&#128176; Competitive pricing</strong><em>Amazon built market share through LOW prices, not monopoly extraction</em></div></div>\n')
w('<div class="dp"><div><strong>&#127775; Innovation value</strong><em>AWS, Prime Video, Alexa &mdash; new products customers value highly</em></div></div>\n')
w('</div>\n')
w('<div class="ds rs"><div class="dh r">&#128308; YES at Employees\' Expense</div>\n')
