w('<div class="dp"><div><strong>&#128100; Monopsony power</strong><em>Amazon = 45% of US e-commerce; dominant employer in many regions</em></div></div>\n')
w('<div class="dp"><div><strong>&#128274; Anti-union practices</strong><em>Documented union-busting; workers lack bargaining power to capture value created</em></div></div>\n')
w('<div class="dp"><div><strong>&#128202; Wage suppression</strong><em>Median Amazon wage below living wage in many markets until $15 minimum (2018)</em></div></div>\n')
w('</div>\n</div>\n')
w('<div class="sh">&#128203; Key Data</div>\n')
w('<div class="datagrid">\n')
